typedef struct _PDH_COUNTER_PATH_ELEMENTS_W {
LPWSTR szMachineName;   LPWSTR szObjectName;   LPWSTR szInstanceName;
LPWSTR szParentInstance;   DWORD  dwInstanceIndex;   LPWSTR szCounterName;
} PDH_COUNTER_PATH_ELEMENTS_W, *PPDH_COUNTER_PATH_ELEMENTS_W;
成员 szMachineName
指向以 null 结尾的字符串的指针，该字符串指定计算机名称。 szObjectName
指向以 null 结尾的字符串的指针，该字符串指定对象名称。 szInstanceName
指向以 null 结尾的字符串的指针，该字符串指定实例名称。 可以包含通配符。 szParentInstance
指向以 null 结尾的字符串的指针，该字符串指定父实例名称。 可以包含通配符。 dwInstanceIndex
用于唯一标识重复实例名称的索引。 szCounterName
指向以 null 结尾的字符串的指针，该字符串指定计数器名称。

typedef struct _PDH_DATA_ITEM_PATH_ELEMENTS_W {   LPWSTR szMachineName;
GUID   ObjectGUID;   DWORD  dwItemId;
LPWSTR szInstanceName;
} PDH_DATA_ITEM_PATH_ELEMENTS_W, *PPDH_DATA_ITEM_PATH_ELEMENTS_W;
成员 szMachineName
指向以 null 结尾的字符串的指针，该字符串指定数据项所在的计算机的名称。 ObjectGUID
数据项所在的对象的 GUID。 dwItemId
数据项的标识符。 szInstanceName
指向以 null 结尾的字符串的指针，该字符串指定数据项实例的名称。

typedef struct _PDH_FMT_COUNTERVALUE {
DWORD CStatus;   union {
LONG     longValue;     double   doubleValue;     LONGLONG largeValue;
